def _extensions_for_format(format_name: str) -> set[str]:
    mapping = {
        "jpeg": {"jpg", "jpeg"},
        "png": {"png"},
        "gif": {"gif"},
        "bmp": {"bmp"},
        "webp": {"webp"},
        "tiff": {"tif", "tiff"},
        "heic": {"heic", "heif"},
        "pdf": {"pdf"},
    }
    return mapping.get(format_name, set())

