def _build_summary(payload: dict[str, object]) -> str:
    parts = [
        str(payload.get("filename")),
        str(payload.get("format")).upper(),
        "valid" if payload.get("valid") else "invalid",
        f"{payload.get('byte_size', 0):,} bytes",
    ]
    if payload.get("width") and payload.get("height"):
        parts.append(f"{payload['width']}×{payload['height']}")
    warning_count = len(payload.get("warnings", []))
    if warning_count:
        parts.append(f"{warning_count} warning(s)")
    return " · ".join(parts)
